const DisasterMuseumEngine = {ZONES:{earthquake_zone:{name:"🌍 地震体验区",icon:"🌍",desc:"了解地震成因、预警信号和自救方法",exhibits:[{title:"地震成因",content:"地震是地壳快速释放能量产生的振动。地球上主要有三条地震带：环太平洋地震带、欧亚地震带和海岭地震带。中国位于欧亚地震带和环太平洋地震带之间，是地震多发国家。"},{title:"震级与烈度",content:"震级表示地震释放能量的大小，每增加1级能量增加约32倍。烈度表示地面受破坏程度，同一地震不同地区烈度不同。"},{title:"预警原理",content:"地震预警利用电磁波比地震波快的原理。P波（纵波）速度快但破坏小，S波（横波）速度慢但破坏大。在S波到达前发出预警可争取几秒到几十秒的避险时间。"},{title:"家庭防震",content:"固定高大家具、准备应急包、熟悉安全躲避位置（桌子下、承重墙角）、了解燃气阀门和电闸位置。"}]},fire_zone:{name:"🔥 消防安全区",icon:"🔥",desc:"认识火灾隐患、灭火器使用和逃生技巧",exhibits:[{title:"火灾分类",content:"A类：固体火灾（木材、纸张）\nB类：液体火灾（汽油、酒精）\nC类：气体火灾（天然气、液化气）\nD类：金属火灾（钾、钠）\nE类：电气火灾"},{title:"灭火器使用",content:'记住口诀"提、拔、握、压"：提起灭火器→拔掉保险销→握住喷管对准火焰根部→压下压把扫射。注意站在上风向，距离火源2-3米。'},{title:"逃生要点",content:"低姿前行、湿毛巾捂口鼻、摸门把手判断火势、不乘电梯、不贪恋财物。如被困可到窗边挥动鲜艳衣物求救。"},{title:"家庭防火",content:"不超负荷用电、出门前检查燃气和电器、不在楼道堆放杂物、安装烟雾报警器、配备灭火器。"}]},flood_zone:{name:"🌊 防洪抗灾区",icon:"🌊",desc:"了解洪水成因、预警信号和避险方法",exhibits:[{title:"洪水成因",content:"暴雨、台风、冰雪融化、溃坝等都可能引发洪水。城市内涝则与排水系统容量不足、地面硬化率高有关。"},{title:"洪水预警",content:"蓝色预警：可能发生洪水\n黄色预警：将发生较大洪水\n橙色预警：将发生重大洪水\n红色预警：将发生特大洪水"},{title:"避险方法",content:"向高处转移、不要涉水过河、远离电线杆和大树、准备救生设备。如被洪水包围，可爬上屋顶等待救援，挥动鲜艳物品求救。"},{title:"城市防涝",content:"暴雨天避免进入地下空间（地铁、地下商场）、远离低洼积水路段、不要强行通过积水桥洞。"}]},general_zone:{name:"📚 综合安全区",icon:"📚",desc:"日常安全、急救常识与应急准备",exhibits:[{title:"应急包清单",content:"每人家庭应备：饮用水（3天量）、食物（压缩饼干等）、手电筒、急救包、哨子、身份证复印件、现金、充电宝、雨衣、保暖毯。"},{title:"急救电话",content:"中国急救电话：120（医疗急救）、119（火警）、110（报警）、122（交通事故）。拨打时说清地点、伤情、人数。"},{title:"海姆立克急救",content:"异物卡喉（气道梗阻）时，站其身后双手环抱腹部，一手握拳抵住肚脐上方两横指，另一手包住快速向内向上冲击，直到异物排出。"},{title:"外伤止血",content:"出血时先压迫伤口近心端止血，用干净纱布加压包扎；大出血可用止血带并记录时间，每40-60分钟放松一次，尽快送医。"}]},typhoon_zone:{name:"🌪️ 台风防御区",icon:"🌪️",desc:"台风成因、预警信号与防风避险",exhibits:[{title:"台风成因",content:"台风是热带或副热带洋面上形成的强烈热带气旋，中心附近最大风力≥12级。西北太平洋是全球台风最活跃的区域，我国东南沿海夏秋季节受影响最大。"},{title:"预警信号",content:"台风分蓝、黄、橙、红四级预警。蓝色：24小时内可能受影响；黄色：24小时内将受影响；橙色：12小时内将受影响；红色：6小时内将受强风影响。"},{title:"防风准备",content:"提前加固门窗、收好阳台花盆等易坠物，储备食物饮水与充电宝，车辆移至高处，远离临时建筑和广告牌、大树，检查排水畅通。"},{title:"台风眼误区",content:"台风中心“台风眼”内风平浪静，但眼壁风力最强。眼过后风向反转、风雨再袭，此时切勿提前出门，应继续待在安全室内。"}]},lightning_zone:{name:"⚡ 雷电防护区",icon:"⚡",desc:"雷电成因、室内外防护与雷击急救",exhibits:[{title:"雷电成因",content:"云层内电荷分离，正负电荷击穿空气产生放电。雷暴多发生在夏季午后和山区，常伴随强降雨和阵风。"},{title:"室外避险",content:"远离孤立大树、高处、金属物体和水面；不打金属伞；双脚并拢蹲下减少跨步电压；不要成群站立，彼此拉开距离。"},{title:"室内防护",content:"关好门窗、远离金属管线和墙壁；拔掉电器插头；不使用太阳能热水器洗澡；不打有线电话；雷暴时少用淋浴。"},{title:"雷击急救",content:"雷击常导致心脏骤停而非“电死”。立即判断呼吸心跳，无反应马上做心肺复苏（CPR）并拨打120；雷击伤员通常仍有救治希望，不要轻易放弃。"}]},landslide_zone:{name:"🏔️ 泥石流滑坡区",icon:"🏔️",desc:"泥石流滑坡的前兆识别与避险自救",exhibits:[{title:"形成条件",content:"陡峭山坡、松散土石加上强降雨或冰雪融化易引发泥石流和滑坡。沟谷中水流突然变浑、水位骤涨是最直接的征兆。"},{title:"前兆识别",content:"动物惊逃、沟谷传来异常轰鸣、泉水干涸或变浑、斜坡出现新裂缝、树木歪斜或房屋开裂，都可能是滑坡泥石流的先兆。"},{title:"避险路线",content:"向与沟谷垂直的两侧高处跑，切忌顺沟向上或向下跑；避开低洼处和河道转弯处；提前规划逃生路线，听到警报立即撤离。"},{title:"被埋自救",content:"保持冷静、掩住口鼻防呛、节省体力；用石块或金属物敲击发出求救信号；不要盲目大声呼喊或挣扎，保存体力等待救援。"}]},tornado_zone:{name:"🌀 龙卷风防护区",icon:"🌀",desc:"龙卷风特点与室内外避险方法",exhibits:[{title:"龙卷特点",content:"龙卷风是高速旋转的气柱，破坏力极强但路径窄、持续时间短，常伴随强雷暴（超级单体）出现，多发于平原地区。"},{title:"预警信号",content:"看到漏斗云、天空呈墨绿色、听到类似火车或飞机的持续轰鸣时，应警惕龙卷风。气象台发布龙卷预警后立刻避险。"},{title:"室内避险",content:"躲到无窗的内室（地下室、卫生间、走廊），远离外墙和窗户；用垫子、被子护住头部；不要待在活动板房和大型场馆中央。"},{title:"户外与车中",content:"弃车到附近低洼处平躺护头；不要躲在桥下或高架下；远离移动房屋和大型车辆；远离电线杆与广告牌。"}]},snow_zone:{name:"❄️ 暴雪寒潮区",icon:"❄️",desc:"寒潮暴雪、道路结冰与取暖安全",exhibits:[{title:"寒潮预警",content:"寒潮分蓝、黄、橙、红四级预警，伴随剧烈降温、大风和降雪。降雪后易形成道路结冰，出行风险显著上升。"},{title:"出行安全",content:"穿防滑鞋、走已清扫路面、远离广告牌和树枝；驾车减速慢行、保持车距、避免急刹；减少不必要的外出。"},{title:"冻伤防护",content:"注意保暖手脚、耳朵和面部；冻伤处勿用力揉搓，用约40℃温水缓慢复温；出现麻木、发白、水疱及时就医。"},{title:"取暖安全",content:"燃煤、炭火取暖务必保持通风，谨防一氧化碳中毒；建议安装一氧化碳报警器；睡前熄灭明火，不在密闭车内开暖气。"}]},heat_zone:{name:"☀️ 高温中暑区",icon:"☀️",desc:"高温预警、中暑分级与现场处理",exhibits:[{title:"高温预警",content:"高温分黄、橙、红三级预警。气温≥35℃为高温，≥37℃为酷暑，≥40℃为强高温，应尽量减少户外活动。"},{title:"中暑分级",content:"先兆中暑（头晕多汗）→轻症中暑（体温升高、恶心呕吐）→重症中暑（热射病，体温>40℃、意识模糊，可致命）。热射病需立即抢救。"},{title:"现场处理",content:"立即转移到阴凉通风处、解开衣物、用冷水擦拭或扇风降温、补充淡盐水；热射病要边降温边拨打120送医，分秒必争。"},{title:"户外防护",content:"避开11—16时高温时段、戴宽檐帽遮阳、少量多次饮水、随身携带防暑药品；出现不适立即休息，不可硬撑。"}]},tsunami_zone:{name:"🌊 海啸防御区",icon:"🌊",desc:"海啸成因、预警信号与高地避险",exhibits:[{title:"海啸成因",content:"海底地震、火山喷发或海底滑坡激起长浪，越靠近岸边浪越高。海啸在远洋传播极快（约700公里/小时），几无征兆。"},{title:"最强前兆",content:"近岸海水异常急速退去（海滩大面积裸露）、动物惊逃，是海啸即将到来的最强前兆，此时绝不要下海捡鱼或观望。"},{title:"避险行动",content:"接到预警或见海水暴退，立即向高处（海拔≥30米）或内陆方向撤离；远离港口、河口和低洼地带；不乘电梯，走楼梯。"},{title:"回流危险",content:"第一波过后往往还有多波，间隔数十分钟到数小时，且后续可能更强。未获官方解除警报前，切勿提前返回岸边。"}]},gas_zone:{name:"💨 燃气泄漏区",icon:"💨",desc:"燃气泄漏识别、禁火禁电与安全处置",exhibits:[{title:"泄漏识别",content:"闻到类似臭鸡蛋的加臭剂气味、燃气表异常转动、附近植物莫名枯萎，都可能是燃气泄漏的信号。"},{title:"禁火禁电",content:"严禁开关任何电器、打火机或电话（在泄漏区内），不要开排风扇或电灯，任何火花都可能引爆泄漏气体。"},{title:"正确处置",content:"立即关闭燃气阀门、轻开门窗通风、到室外安全处拨打燃气公司或119；撤离时动作轻缓，避免金属碰撞产生火花。"},{title:"设备安全",content:"燃气热水器应装在通风良好的室外或半室外；定期检查橡胶软管、使用带熄火保护的灶具；长期不用关闭总阀。"}]},electric_zone:{name:"⚡ 触电防护区",icon:"⚡",desc:"触电原理、断电施救与日常预防",exhibits:[{title:"触电原理",content:"人体是导体，接触带电体并形成回路就会触电。电压越高、身体电阻越小（如湿手、赤脚）越危险。"},{title:"断电施救",content:"施救前先切断电源（拉闸或拔插头）；无法断电时用干燥木棍、塑料等绝缘物挑开电线，切勿直接用手拉拽伤员。"},{title:"心肺复苏",content:"触电者无呼吸心跳时立即做心肺复苏（CPR）并拨打120；持续按压直到专业救援到达，切勿因“叫不醒”就放弃。"},{title:"日常预防",content:"不湿手触摸插座、不用破损电线、雷雨天减少用电、不私拉乱接；家庭建议安装漏电保护器（漏保）并定期测试。"}]},traffic_zone:{name:"🚗 交通安全区",icon:"🚗",desc:"步行、骑车、乘车安全与事故应对",exhibits:[{title:"步行安全",content:"走人行道和斑马线，红灯停绿灯行；不在车流中穿行；夜间穿浅色或带反光的衣物，过马路先左看右看再左看。"},{title:"骑车安全",content:"佩戴头盔、不逆行、不闯红灯、不与机动车抢道；夜间开车灯；雨雪天减速，避免急刹侧滑。"},{title:"乘车安全",content:"系好安全带、不将头手伸出窗外、儿童使用安全座椅、不乘坐黑车和超员车；下车前观察后方来车。"},{title:"事故应对",content:"开启双闪、在车后放置警示牌、人员撤离到安全地带；拍照取证后拨打122和120，说明地点、伤亡和车辆情况。"}]},stampede_zone:{name:"👥 防踩踏区",icon:"👥",desc:"人群密集场所的风险识别与自护",exhibits:[{title:"风险识别",content:"人流密集、移动缓慢、出现“人浪”、有人跌倒、出入口和狭窄通道处最危险；一旦察觉拥挤应立即离开核心区。"},{title:"自我保护",content:"双臂在胸前交叉护住胸口（留出呼吸空间）、顺人流方向行走、不逆流、不弯腰捡东西、不系鞋带，保持重心稳定。"},{title:"倒地自护",content:"如被推倒，侧身蜷缩成球状（虾状）、双手护住头颈、双膝并拢、尽量让胸腔有空间，待人流过后再起身。"},{title:"场所选择",content:"参加大型活动选靠边、靠近出口的位置；提前看清逃生通道；带小孩用背带不离手，避免被人群冲散。"}]},food_zone:{name:"🍱 食品安全区",icon:"🍱",desc:"食物中毒识别、处理与储存卫生",exhibits:[{title:"中毒识别",content:"进食后数分钟至数小时出现恶心、呕吐、腹痛、腹泻、头晕，尤其多人同餐同时发病时，应高度警惕食物中毒。"},{title:"现场处理",content:"清醒者可用手指刺激咽部催吐，保留剩余食物和呕吐物送检，多喝温水，尽快就医并说明同食人员，便于溯源。"},{title:"储存卫生",content:"生熟分开、食物煮熟煮透、剩菜冷藏不超过24小时；冰箱不是保险箱，取出后需充分加热再食用。"},{title:"野食危险",content:"不采食野生蘑菇和野果（剧毒难辨）、不吃发芽土豆和霉变花生、慎食隔夜凉菜；购买食品看清保质期和包装。"}]}},currentZone:null,enterZone(zoneId){var z=this.ZONES[zoneId];if(!z)return;this.currentZone=z;var mp=GameState._data.museumProgress||(GameState._data.museumProgress={}),vis=mp.visited||(mp.visited=[]);if(vis.indexOf(zoneId)<0){GameState.addCoins(5),GameState.addExp(3),vis.push(zoneId),GameState._data.stats.museumVisited=(GameState._data.stats.museumVisited||0)+1,GameState.save()}this.showZone(zoneId)},showZone(zoneId){var z=this.ZONES[zoneId];if(!z)return;var html='<div style=\'padding:16px\'>';html+='<button class=\'btn\' style=\'display:inline-flex;align-items:center;gap:6px;margin:4px 0 16px;background:rgba(255,255,255,0.08);border:1px solid rgba(255,255,255,0.15);border-radius:10px;padding:8px 14px;color:rgba(255,255,255,0.85);cursor:pointer\' onclick=\'DisasterMuseumEngine.exitZone()\'>← 返回展区</button>';html+='<div style=\'text-align:center;margin-bottom:18px\'><div style=\'font-size:3rem\'>'+z.icon+'</div><h3 style=\'color:rgba(255,255,255,0.95);margin:6px 0\'>'+z.name+'</h3><p style=\'font-size:13px;color:rgba(255,255,255,0.55)\'>'+z.desc+'</p></div>';z.exhibits.forEach(function(ex){html+=DisasterMuseumEngine.renderExhibit(ex)}),html+='</div>';var el=document.getElementById('museum-content');el&&(el.innerHTML=html);var page=document.getElementById('page-museum');page&&(page.scrollTop=0)},exitZone(){this.currentZone=null;var el=document.getElementById('museum-content');el&&(el.innerHTML=this.render())},renderExhibit:exhibit=>'<div style="background:rgba(0,0,0,0.2);border-radius:12px;padding:16px;margin:8px 0"><div style="font-weight:700;color:var(--color-primary,#00d4ff);margin-bottom:8px">'+exhibit.title+'</div><div style="font-size:13px;color:rgba(255,255,255,0.8);line-height:1.6;white-space:pre-line">'+exhibit.content+"</div></div>",render(){var html='<div style=\'padding:16px\'>';html+='<div style=\'text-align:center;margin-bottom:20px\'><div style=\'font-size:3rem\'>🏛️</div><h3 style=\'color:rgba(255,255,255,0.95)\'>虚拟防灾馆</h3></div>';for(var id in this.ZONES){var z=this.ZONES[id];html+='<div onclick=\'DisasterMuseumEngine.enterZone(\"'+id+'\")\' style=\'background:rgba(255,255,255,0.03);border:1px solid rgba(255,255,255,0.08);border-radius:14px;padding:16px;margin:8px 0;cursor:pointer\'>';html+='<div style=\'display:flex;align-items:center;gap:12px\'>';html+='<div style=\'font-size:2rem\'>'+z.icon+'</div>';html+='<div style=\'flex:1\'>';html+='<div style=\'font-weight:700;color:rgba(255,255,255,0.9)\'>'+z.name+'</div>';html+='<div style=\'font-size:0.8rem;color:rgba(255,255,255,0.5)\'>'+z.desc+'</div>';html+='</div>';html+='<div style=\'color:rgba(255,255,255,0.3)\'>→</div>';html+='</div></div>';}html+='</div>';return html;}};


